import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.filter.js";
import "core-js/modules/es.iterator.find.js";
import "core-js/modules/es.iterator.for-each.js";
import "core-js/modules/es.json.parse.js";
import LogPanel from '@/components/LogPanel.vue';
import UploadZone from '@/components/UploadZone.vue';
import ResultPanel from '@/components/ResultPanel.vue';
import { validateImage, fileToDataURL, getImageDimensions, formatFileSize } from '@/utils/imageUtils';
import { checkHealth } from '@/api/pigModel';
import { getFarms, createFarm, updateFarm, deleteFarm } from '@/api/farmApi';
import { getDetectionStats } from '@/api/detectionApi';
export default {
  name: 'App',
  components: {
    LogPanel,
    UploadZone,
    ResultPanel
  },
  data() {
    return {
      checkingService: false,
      showImagePreview: false,
      // 猪场相关数据
      farms: [],
      selectedFarmId: null,
      showFarmModal: false,
      newFarmName: '',
      isAddingFarm: false,
      editingFarmId: null,
      editingFarmName: '',
      // 系统统计数据
      systemStats: {
        total_images: 0,
        total_pigs: 0,
        today_images: 0,
        today_pigs: 0,
        avg_processing_time_ms: 0
      },
      // 自定义下拉状态
      showFarmDropdown: false,
      // 顶部提示栏
      showToast: false,
      toastMessage: '',
      toastType: 'toast-info',
      // toast-info, toast-error, toast-success
      toastIcon: 'ℹ️',
      showToastProgress: false,
      toastProgress: 0
    };
  },
  computed: {
    hasImages() {
      return this.$store.getters.hasImages;
    },
    imageCount() {
      return this.$store.getters.imageCount;
    },
    hasResults() {
      return this.$store.getters.hasResults;
    },
    totalPigs() {
      return this.$store.getters.totalPigs;
    },
    isAnalyzing() {
      return this.$store.state.isAnalyzing;
    },
    uploadProgress() {
      return this.$store.state.uploadProgress;
    },
    results() {
      return this.$store.state.results;
    },
    year() {
      return new Date().getFullYear();
    },
    serviceClass() {
      const s = this.$store.state.serviceOnline;
      if (s === null) return 'service-unknown';
      return s ? 'service-online' : 'service-offline';
    },
    serviceLabel() {
      if (this.checkingService) return '检测中…';
      const s = this.$store.state.serviceOnline;
      if (s === null) return '状态未知';
      return s ? '服务正常' : '离线 / Mock';
    },
    currentFarmName() {
      const farm = this.farms.find(f => f.id === this.selectedFarmId);
      return farm ? farm.name : '未选择';
    }
  },
  watch: {},
  created() {
    this.checkServiceHealth();
  },
  mounted() {
    window.addEventListener('mousemove', this.onMouseMove);
    window.addEventListener('keydown', this.onKeyDown);
    document.addEventListener('click', this.handleClickOutside);
  },
  beforeDestroy() {
    window.removeEventListener('mousemove', this.onMouseMove);
    window.removeEventListener('keydown', this.onKeyDown);
    document.removeEventListener('click', this.handleClickOutside);
  },
  methods: {
    toggleFarmDropdown() {
      this.showFarmDropdown = !this.showFarmDropdown;
    },
    handleClickOutside(e) {
      if (this.$refs.farmSelectWrap && !this.$refs.farmSelectWrap.contains(e.target)) {
        this.showFarmDropdown = false;
      }
    },
    selectFarm(farmId) {
      this.selectedFarmId = farmId;
      this.showFarmDropdown = false;
      this.onFarmChange();
    },
    onKeyDown(e) {
      if (e.key === 'Escape' && this.showImagePreview) {
        this.closeImagePreview();
      }
    },
    getAnalyzeBtnTitle() {
      if (!this.selectedFarmId) return '请先选择猪场';
      if (!this.$store.state.serviceOnline) return '后端服务离线，请检查服务状态';
      if (!this.hasImages) return '请先上传图片';
      return '';
    },
    onMouseMove(e) {
      const mx = e.clientX / window.innerWidth - 0.5;
      const my = e.clientY / window.innerHeight - 0.5;
      const o1 = document.querySelector('.orb-1');
      const o2 = document.querySelector('.orb-2');
      if (o1) o1.style.transform = 'translate(' + mx * 30 + 'px,' + my * 30 + 'px)';
      if (o2) o2.style.transform = 'translate(' + -mx * 20 + 'px,' + -my * 20 + 'px)';
    },
    cardFloatIn(e) {
      const card = e.currentTarget;
      card._tiltFn = ev => {
        const r = card.getBoundingClientRect();
        const cx = (ev.clientX - r.left) / r.width - 0.5;
        const cy = (ev.clientY - r.top) / r.height - 0.5;
        card.style.transform = 'perspective(800px) rotateX(' + -cy * 3 + 'deg) rotateY(' + cx * 3 + 'deg) translateY(-2px)';
      };
      card.addEventListener('mousemove', card._tiltFn);
    },
    cardFloatOut(e) {
      const card = e.currentTarget;
      if (card._tiltFn) card.removeEventListener('mousemove', card._tiltFn);
      card.style.transform = '';
    },
    openImagePreview() {
      if (this.hasResult && this.annotatedImage) {
        this.showImagePreview = true;
        document.body.style.overflow = 'hidden';
      }
    },
    closeImagePreview() {
      this.showImagePreview = false;
      document.body.style.overflow = '';
    },
    showToastMessage(message, type = 'toast-info', duration = 3000) {
      this.toastMessage = message;
      this.toastType = type;
      this.toastIcon = type === 'toast-info' ? 'ℹ️' : type === 'toast-error' ? '⚠️' : '✅';
      this.showToast = true;
      this.showToastProgress = false;
      if (duration > 0) {
        setTimeout(() => this.closeToast(), duration);
      }
    },
    showToastWithProgress(message, type = 'toast-info') {
      this.toastMessage = message;
      this.toastType = type;
      this.toastIcon = type === 'toast-info' ? 'ℹ️' : type === 'toast-error' ? '⚠️' : '✅';
      this.showToast = true;
      this.showToastProgress = true;
      this.toastProgress = 0;
    },
    updateToastProgress(progress) {
      this.toastProgress = progress;
    },
    closeToast() {
      this.showToast = false;
    },
    onImagesLoaded(images) {
      this.showToastMessage(`已加载 ${images.length} 个文件`, 'toast-success', 3000);
    },
    clearAll() {
      this.$store.commit('CLEAR_IMAGES');
      this.$store.commit('ADD_LOG', {
        msg: '已清除所有图片',
        type: 'info'
      });
    },
    async runAnalysis() {
      if (!this.hasImages || this.isAnalyzing || !this.selectedFarmId) return;
      if (!this.$store.state.serviceOnline) {
        this.$store.commit('ADD_LOG', {
          msg: '⚠️ 后端服务离线，无法识别图片',
          type: 'error'
        });
        this.showToastMessage('后端服务离线，无法识别图片', 'toast-error', 4000);
        return;
      }
      const btn = this.$refs.analyzeBtn;
      if (btn) {
        btn.style.transform = 'scale(0.93)';
        setTimeout(() => {
          btn.style.transform = '';
        }, 150);
      }
      this.$store.commit('SET_ANALYZING', true);
      this.$store.commit('SET_PROGRESS', 0);
      this.$store.commit('ADD_LOG', {
        msg: '发送至数猪大模型…',
        type: 'info'
      });

      // 显示带进度的顶部提示栏
      this.showToastWithProgress('正在识别图片...', 'toast-info');
      try {
        const images = this.$store.state.images;
        const formData = new FormData();

        // 添加文件
        images.forEach(image => {
          formData.append('files', image.file);
        });

        // 添加其他参数
        formData.append('farm_id', this.selectedFarmId);
        formData.append('conf_threshold', 0.25);
        formData.append('iou_threshold', 0.45);
        formData.append('imgsz', 960);

        // 上传进度
        const xhr = new XMLHttpRequest();
        xhr.upload.addEventListener('progress', e => {
          if (e.lengthComputable) {
            const progress = Math.round(e.loaded / e.total * 100);
            this.$store.commit('SET_PROGRESS', progress);
            this.updateToastProgress(progress);
          }
        });

        // 发送请求
        const response = await new Promise((resolve, reject) => {
          xhr.open('POST', '/api/batch-predict');
          xhr.onload = () => {
            if (xhr.status === 200) {
              resolve(JSON.parse(xhr.responseText));
            } else {
              reject(new Error(JSON.parse(xhr.responseText).detail || '分析失败'));
            }
          };
          xhr.onerror = () => reject(new Error('网络错误'));
          xhr.send(formData);
        });
        this.$store.commit('SET_RESULTS', response);
        this.$store.commit('SET_PROGRESS', 100);
        this.updateToastProgress(100);

        // 显示识别成功提示
        setTimeout(() => {
          this.showToastMessage(`识别完成：${response.total_images} 张图片，共检测到 ${response.total_pigs} 头猪`, 'toast-success', 4000);
        }, 500);
        this.$store.commit('ADD_LOG', {
          msg: `识别完成：${response.total_images} 张图片，共检测到 ${response.total_pigs} 头猪`,
          type: 'success'
        });
        // 识别成功后刷新统计数据
        await this.loadDetectionStats();
      } catch (err) {
        this.$store.commit('ADD_LOG', {
          msg: '识别失败：' + err.message,
          type: 'error'
        });
        this.showToastMessage('识别失败：' + err.message, 'toast-error', 4000);
      } finally {
        this.$store.commit('SET_ANALYZING', false);
        // 延迟关闭提示栏，让用户看到完成状态
        setTimeout(() => this.closeToast(), 1000);
      }
    },
    async checkServiceHealth() {
      this.checkingService = true;
      try {
        const online = await checkHealth();
        this.$store.commit('SET_SERVICE_STATUS', online);
        this.$store.commit('ADD_LOG', {
          msg: online ? '服务在线' : '服务未响应（Mock 模式）',
          type: online ? 'success' : 'warn'
        });
        // 服务在线时加载猪场列表和统计数据
        if (online) {
          await this.loadFarms();
          await this.loadDetectionStats();
        }
      } catch {
        this.$store.commit('SET_SERVICE_STATUS', false);
      } finally {
        this.checkingService = false;
      }
    },
    // ========== 统计数据方法 ==========
    async loadDetectionStats() {
      try {
        const response = await getDetectionStats(this.selectedFarmId);
        if (response.success) {
          this.systemStats = response.data;
        }
      } catch (err) {
        console.error('加载统计数据失败:', err);
      }
    },
    // ========== 猪场管理方法 ==========
    async loadFarms() {
      try {
        const response = await getFarms();
        if (response.success) {
          this.farms = response.data;
          this.$store.commit('ADD_LOG', {
            msg: `已加载 ${this.farms.length} 个猪场`,
            type: 'info'
          });
        }
      } catch (err) {
        this.$store.commit('ADD_LOG', {
          msg: '加载猪场列表失败：' + err.message,
          type: 'error'
        });
      }
    },
    async onFarmChange() {
      const farm = this.farms.find(f => f.id === this.selectedFarmId);
      if (farm) {
        this.$store.commit('ADD_LOG', {
          msg: `已选择猪场：${farm.name}`,
          type: 'info'
        });
      }
      // 切换猪场后刷新统计数据
      await this.loadDetectionStats();
    },
    closeFarmModal() {
      this.showFarmModal = false;
      this.newFarmName = '';
      this.editingFarmId = null;
      this.editingFarmName = '';
    },
    async addFarm() {
      const name = this.newFarmName.trim();
      if (!name) return;
      this.isAddingFarm = true;
      try {
        const response = await createFarm(name);
        if (response.success) {
          this.farms.unshift(response.data);
          this.newFarmName = '';
          this.$store.commit('ADD_LOG', {
            msg: `成功添加猪场：${response.data.name}`,
            type: 'success'
          });
        }
      } catch (err) {
        this.$store.commit('ADD_LOG', {
          msg: '添加猪场失败：' + err.message,
          type: 'error'
        });
      } finally {
        this.isAddingFarm = false;
      }
    },
    startEditFarm(farm) {
      this.editingFarmId = farm.id;
      this.editingFarmName = farm.name;
      this.$nextTick(() => {
        const input = this.$refs.editInput;
        if (input && input[0]) input[0].focus();
      });
    },
    cancelEditFarm() {
      this.editingFarmId = null;
      this.editingFarmName = '';
    },
    async saveEditFarm() {
      const name = this.editingFarmName.trim();
      if (!name || name === this.farms.find(f => f.id === this.editingFarmId)?.name) {
        this.cancelEditFarm();
        return;
      }
      try {
        const response = await updateFarm(this.editingFarmId, name);
        if (response.success) {
          const index = this.farms.findIndex(f => f.id === this.editingFarmId);
          if (index !== -1) {
            this.farms.splice(index, 1, response.data);
          }
          this.$store.commit('ADD_LOG', {
            msg: `成功更新猪场：${response.data.name}`,
            type: 'success'
          });
        }
      } catch (err) {
        this.$store.commit('ADD_LOG', {
          msg: '更新猪场失败：' + err.message,
          type: 'error'
        });
      } finally {
        this.editingFarmId = null;
        this.editingFarmName = '';
      }
    },
    async deleteFarmById(farmId) {
      const farm = this.farms.find(f => f.id === farmId);
      if (!farm) return;
      if (!confirm(`确定要删除猪场"${farm.name}"吗？`)) return;
      try {
        const response = await deleteFarm(farmId);
        if (response.success) {
          this.farms = this.farms.filter(f => f.id !== farmId);
          if (this.selectedFarmId === farmId) {
            this.selectedFarmId = null;
          }
          this.$store.commit('ADD_LOG', {
            msg: `成功删除猪场：${farm.name}`,
            type: 'success'
          });
        }
      } catch (err) {
        this.$store.commit('ADD_LOG', {
          msg: '删除猪场失败：' + err.message,
          type: 'error'
        });
      }
    },
    formatFarmDate(dateStr) {
      if (!dateStr) return '';
      const date = new Date(dateStr);
      return date.toLocaleDateString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit'
      });
    },
    // ========== 批量上传相关方法 ==========
    onBatchFilesLoaded(files) {
      this.showToastMessage(`已加载 ${files.length} 个文件`, 'toast-success', 3000);
    },
    async onBatchAnalyzed(result) {
      this.showToastMessage(`批量分析完成：${result.total_images} 张图片，共识别 ${result.total_pigs} 头猪`, 'toast-success', 4000);
      // 批量分析完成后刷新统计数据
      await this.loadDetectionStats();
    }
  }
};
